{"result":"{
  "name": "doc_coauthoring",
  "entrypoint": "start_doc",
  "actions": [
    {
      "name": "start_doc",
      "description": "Start the doc workflow. Captures the SKILL's meta-context\n(doc type, audience, desired impact, optional template reference)\nand emits the Stage-1 context-dump prompt.\n\nArgs:\n    doc_type: What kind of doc this is. E.g. \"decision doc\",\n        \"technical spec\", \"PRD\", \"incident postmortem\", \"RFC\".\n    audience: Who reads it. E.g. \"engineering leadership\",\n        \"the platform team\", \"external developers using our API\".\n    desired_impact: What changes when someone reads it. E.g.\n        \"decision approved by EOW\", \"spec implementable without\n        further clarification\", \"new hires can onboard in <2 days\".\n    template: Optional. Pointer or summary of a template/format\n        to follow. The SKILL says to ask about this up front.",
      "reads": [],
      "writes": [
        "doc_type",
        "audience",
        "desired_impact",
        "template_summary",
        "context_dump",
        "sources_consulted",
        "clarifications",
        "sections",
        "section_drafts",
        "final_review_notes",
        "reader_questions",
        "reader_results",
        "reader_issues",
        "final_doc",
        "current_prompt",
        "log"
      ],
      "required_inputs": [
        "doc_type",
        "audience",
        "desired_impact"
      ],
      "optional_inputs": [
        "template"
      ]
    },
    {
      "name": "gather_context",
      "description": "Stash the Stage-1 info dump. Refuses thin dumps as action_error\nso the agent cannot speed-run past context gathering.",
      "reads": [
        "log"
      ],
      "writes": [
        "context_dump",
        "sources_consulted",
        "current_prompt",
        "log"
      ],
      "required_inputs": [
        "context_dump"
      ],
      "optional_inputs": [
        "sources_consulted"
      ]
    },
    {
      "name": "confirm_context",
      "description": "Stash clarifying-question artifacts and gate the exit from\nStage 1. The SKILL says context is sufficient when \"edge cases\nand trade-offs can be asked about without needing basics\nexplained\"; the FSM proxy for that is a minimum number of\nstructured clarifications.",
      "reads": [
        "doc_type",
        "audience",
        "log"
      ],
      "writes": [
        "clarifications",
        "current_prompt",
        "log"
      ],
      "required_inputs": [
        "clarifications"
      ],
      "optional_inputs": []
    },
    {
      "name": "agree_structure",
      "description": "Lock the section list for Stage 2. The FSM remembers these\nnames so ``draft_section`` can refuse unknown names and\n``complete_drafting`` can refuse premature exit.",
      "reads": [
        "log"
      ],
      "writes": [
        "sections",
        "section_drafts",
        "current_prompt",
        "log"
      ],
      "required_inputs": [
        "sections"
      ],
      "optional_inputs": []
    },
    {
      "name": "draft_section",
      "description": "Record one section's draft. Loop-able: call again with the\nsame ``section_name`` to revise; call with a new name to advance.\n\nRefuses ``section_name`` not in the agreed list as action_error.",
      "reads": [
        "sections",
        "section_drafts",
        "log"
      ],
      "writes": [
        "section_drafts",
        "current_prompt",
        "log"
      ],
      "required_inputs": [
        "section_name",
        "drafted_content"
      ],
      "optional_inputs": [
        "brainstorm_options",
        "kept_options"
      ]
    },
    {
      "name": "complete_drafting",
      "description": "Gate the Stage 2 exit. Refuses if any agreed section is still\nundrafted. The SKILL warns about generic filler and missed\nsections; the FSM makes \"all agreed sections have a draft\" a\nstructural invariant before reader testing can start.",
      "reads": [
        "section_drafts",
        "log"
      ],
      "writes": [
        "final_review_notes",
        "current_prompt",
        "log"
      ],
      "required_inputs": [
        "final_review_notes"
      ],
      "optional_inputs": []
    },
    {
      "name": "reader_test",
      "description": "Run the Stage 3 reader-testing artifact submission. If any\nissue is severity=='blocking', the FSM routes back into\n``draft_section`` for the affected section. Otherwise it opens\nthe path to ``finalize_doc``.",
      "reads": [
        "sections",
        "section_drafts",
        "log"
      ],
      "writes": [
        "reader_questions",
        "reader_results",
        "reader_issues",
        "has_blocking_issues",
        "current_prompt",
        "log"
      ],
      "required_inputs": [
        "predicted_questions",
        "test_results"
      ],
      "optional_inputs": [
        "issues_found"
      ]
    },
    {
      "name": "finalize_doc",
      "description": "Terminal. Refuses if Stage 3 left any blocking issues open.",
      "reads": [
        "doc_type",
        "audience",
        "desired_impact",
        "sections",
        "section_drafts",
        "reader_issues",
        "log"
      ],
      "writes": [
        "final_doc",
        "doc_summary",
        "current_prompt",
        "log"
      ],
      "required_inputs": [
        "final_doc"
      ],
      "optional_inputs": []
    }
  ],
  "transitions": [
    {
      "from": "start_doc",
      "to": "gather_context",
      "condition": null
    },
    {
      "from": "gather_context",
      "to": "confirm_context",
      "condition": null
    },
    {
      "from": "confirm_context",
      "to": "agree_structure",
      "condition": null
    },
    {
      "from": "agree_structure",
      "to": "draft_section",
      "condition": null
    },
    {
      "from": "draft_section",
      "to": "draft_section",
      "condition": "None in section_drafts.values()"
    },
    {
      "from": "draft_section",
      "to": "complete_drafting",
      "condition": "None not in section_drafts.values()"
    },
    {
      "from": "complete_drafting",
      "to": "reader_test",
      "condition": null
    },
    {
      "from": "reader_test",
      "to": "draft_section",
      "condition": "has_blocking_issues"
    },
    {
      "from": "reader_test",
      "to": "finalize_doc",
      "condition": "not has_blocking_issues"
    }
  ],
  "state_schema": null,
  "meta_tools": [
    {
      "name": "reset_session",
      "description": "Reset this session's FSM to its entrypoint, clearing sub-runs and appending a reset marker to history. Always callable regardless of FSM state. Refuses in shared-app mode."
    },
    {
      "name": "fork_at",
      "description": "Rewind the session to the state captured after a specific history entry (by ``seq`` from ``burr://history``). Lets an agent explore alternate paths from any checkpoint without losing the audit trail. Refuses in shared-app mode."
    },
    {
      "name": "fork_from_past",
      "description": "Resume a past Burr run by loading its state from disk. Requires the Application to have a LocalTrackingClient. Use for resuming sessions across server restarts or forking from any persisted past app_id."
    }
  ]
}"}

